    }
    if (exec_pragma("PRAGMA busy_timeout=5000;") != 0) {
        pthread_mutex_unlock(&db_mu);
        return -1;
    }

    const char *sql =
        "CREATE TABLE IF NOT EXISTS notes ("
        "id INTEGER PRIMARY KEY AUTOINCREMENT,"
        "title TEXT NOT NULL,"
