        ");";

    char *err_msg = NULL;
    if (sqlite3_exec(db, sql, NULL, NULL, &err_msg) != SQLITE_OK) {
        fprintf(stderr, "SQL error: %s\n", err_msg);
        sqlite3_free(err_msg);
        pthread_mutex_unlock(&db_mu);
        return -1;
    }

    pthread_mutex_unlock(&db_mu);
    return 0;
}

void close_db(void) {
    pthread_mutex_lock(&db_mu);
    if (db) sqlite3_close(db);
    db = NULL;
    pthread_mutex_unlock(&db_mu);
}

static char *json_escape(const char *s) {
    if (!s) s = "";
    size_t extra = 0;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
        case '"':
        case '\\':
            extra++;
            break;
        case '\b':
        case '\f':
        case '\n':
        case '\r':
        case '\t':
            extra++;
            break;
        default:
            if (*p < 0x20) extra += 5; // \u00XX
            break;
        }
    }

    size_t len = strlen(s);
    char *out = malloc(len + extra + 1);
    if (!out) return NULL;

    char *o = out;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
        case '"':
            *o++ = '\\';
            *o++ = '"';
            break;
        case '\\':
            *o++ = '\\';
            *o++ = '\\';
            break;
        case '\b':
            *o++ = '\\';
            *o++ = 'b';
            break;
        case '\f':
            *o++ = '\\';
            *o++ = 'f';
            break;
        case '\n':
            *o++ = '\\';
            *o++ = 'n';
            break;
        case '\r':
            *o++ = '\\';
            *o++ = 'r';
            break;
        case '\t':
            *o++ = '\\';
            *o++ = 't';
            break;
        default:
            if (*p < 0x20) {
                sprintf(o, "\\u%04x", (unsigned int)(*p));
                o += 6;
            } else {
                *o++ = (char)(*p);
            }
            break;
        }
    }
    *o = '\0';
    return out;
}

int create_note(const char *title, const char *content) {
    pthread_mutex_lock(&db_mu);

    sqlite3_exec(db, "BEGIN IMMEDIATE;", NULL, NULL, NULL);

    const char *sql = "INSERT INTO notes (title, content) VALUES (?, ?);";
    sqlite3_stmt *stmt = NULL;
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return -1;
    }

    sqlite3_bind_text(stmt, 1, title ? title : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content ? content : "", -1, SQLITE_TRANSIENT);

    rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_DONE) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return -1;
    }

    int id = (int)sqlite3_last_insert_rowid(db);
    sqlite3_exec(db, "COMMIT;", NULL, NULL, NULL);

    pthread_mutex_unlock(&db_mu);
    return id;
}

static char *appendf(char *buf, size_t *cap, size_t *len, const char *fmt, ...) {
    va_list ap;
    while (1) {
        if (*cap - *len < 256) {
            *cap = (*cap == 0) ? 1024 : (*cap * 2);
            buf = realloc(buf, *cap);
            if (!buf) return NULL;
        }
        va_start(ap, fmt);
        int n = vsnprintf(buf + *len, *cap - *len, fmt, ap);
        va_end(ap);
        if (n < 0) return NULL;
        if ((size_t)n < *cap - *len) {
            *len += (size_t)n;
            return buf;
        }
        *cap += (size_t)n + 1;
        buf = realloc(buf, *cap);
        if (!buf) return NULL;
    }
}

