static int parse_int(const char *s, int *out) {
    if (!s || !*s) return 0;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (!end || *end != '\0') return 0;
    if (v < 0 || v > 1000000000L) return 0;
    *out = (int)v;
    return 1;
}

static void trim_ws_in_place(char *s) {
    if (!s) return;
    size_t len = strlen(s);
    while (len > 0 && isspace((unsigned char)s[len - 1])) {
        s[len - 1] = '\0';
        len--;
    }
    size_t i = 0;
    while (s[i] && isspace((unsigned char)s[i])) i++;
    if (i > 0) memmove(s, s + i, strlen(s + i) + 1);
}

// Minimal JSON string parser for flat objects containing "title" and "content".
// Only supports double-quoted strings with standard backslash escapes.
static int parse_json_string_value(const char *json, const char *key,
                                  char **out) {
    *out = NULL;
    if (!json || !key) return 0;

    char needle[64];
    snprintf(needle, sizeof(needle), "\"%s\"", key);
    const char *p = strstr(json, needle);
    if (!p) return 0;
    p += strlen(needle);

    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != ':') return 0;
    p++;
    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != '"') return 0;
    p++;

    size_t cap = 128, len = 0;
    char *buf = malloc(cap);
    if (!buf) return 0;

    while (*p) {
        if (*p == '"') {
            p++;
            break;
        }
        unsigned char c = (unsigned char)*p++;
        if (c == '\\') {
            unsigned char e = (unsigned char)*p++;
            switch (e) {
            case '"': c = '"'; break;
            case '\\': c = '\\'; break;
            case '/': c = '/'; break;
            case 'b': c = '\b'; break;
            case 'f': c = '\f'; break;
            case 'n': c = '\n'; break;
            case 'r': c = '\r'; break;
            case 't': c = '\t'; break;
            default:
                free(buf);
                return 0;
            }
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(buf, cap);
            if (!nb) {
                free(buf);
                return 0;
            }
            buf = nb;
        }
        buf[len++] = (char)c;
    }
    buf[len] = '\0';
    *out = buf;
    return 1;
}

static int parse_note_body(const char *json, char **title, char **content) {
    *title = NULL;
    *content = NULL;

    if (!parse_json_string_value(json, "title", title)) return 0;
    if (!parse_json_string_value(json, "content", content)) {
        // content is optional per many APIs; contract says it accepts string
        // title and content. We'll default to empty if missing.
        *content = strdup("");
        if (!*content) {
            free(*title);
            *title = NULL;
            return 0;
        }
    }
    trim_ws_in_place(*title);
    if ((*title)[0] == '\0') return 0;
    return 1;
}

static enum MHD_Result ensure_body_collected(const char *method,
                                            const char *upload_data,
                                            size_t *upload_data_size,
                                            void **con_cls) {
    if (*con_cls == NULL) {
        struct connection_info *ci = calloc(1, sizeof(struct connection_info));
        if (!ci) return MHD_NO;
        *con_cls = ci;
        return MHD_YES;
    }

    struct connection_info *ci = *con_cls;

    if (*upload_data_size > 0) {
        // Enforce contract size limit for POST/PUT bodies.
        if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) &&
            ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
            // Signal caller to respond 413 by using a sentinel size.
            ci->data_size = NOTES_MAX_BODY_BYTES + 1;
            *upload_data_size = 0;
            return MHD_YES;
        }

        char *nb = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!nb) return MHD_NO;
        ci->data = nb;
        memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
        ci->data_size += *upload_data_size;
        ci->data[ci->data_size] = '\0';
        *upload_data_size = 0;
        return MHD_YES;
    }

    return MHD_YES;
}

