static int parse_int(const char *s, int *out) {
    if (!s || !*s) return 0;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (!end || *end != '\0') return 0;
    if (v < 0 || v > 1000000000L) return 0;
    *out = (int)v;
    return 1;
}

static void trim_ws_in_place(char *s) {
    if (!s) return;
    size_t len = strlen(s);
    while (len > 0 && isspace((unsigned char)s[len - 1])) {
        s[len - 1] = '\0';
        len--;
    }
    size_t i = 0;
    while (s[i] && isspace((unsigned char)s[i])) i++;
    if (i > 0) memmove(s, s + i, strlen(s + i) + 1);
}

static int parse_json_string_value(const char *json, const char *key,
                                  char **out) {
    *out = NULL;
    if (!json || !key) return 0;

    char needle[64];
    snprintf(needle, sizeof(needle), "\"%s\"", key);
    const char *p = strstr(json, needle);
    if (!p) return 0;
    p += strlen(needle);

    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != ':') return 0;
    p++;
    while (*p && isspace((unsigned char)*p)) p++;
    if (*p != '"') return 0;
    p++;

    size_t cap = 128, len = 0;
    char *buf = malloc(cap);
    if (!buf) return 0;

    while (*p) {
        if (*p == '"') {
            p++;
            break;
        }
        unsigned char c = (unsigned char)*p++;
        if (c == '\\') {
            unsigned char e = (unsigned char)*p++;
            switch (e) {
            case '"': c = '"'; break;
            case '\\': c = '\\'; break;
            case '/': c = '/'; break;
            case 'b': c = '\b'; break;
            case 'f': c = '\f'; break;
            case 'n': c = '\n'; break;
            case 'r': c = '\r'; break;
            case 't': c = '\t'; break;
            default:
                free(buf);
                return 0;
            }
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(buf, cap);
            if (!nb) {
                free(buf);
                return 0;
            }
            buf = nb;
        }
        buf[len++] = (char)c;
    }
    buf[len] = '\0';
    *out = buf;
    return 1;
}

static int parse_note_body(const char *json, char **title, char **content) {
    *title = NULL;
    *content = NULL;

    if (!parse_json_string_value(json, "title", title)) return 0;
    if (!parse_json_string_value(json, "content", content)) {
        *content = strdup("");
        if (!*content) {
            free(*title);
            *title = NULL;
            return 0;
        }
    }

    trim_ws_in_place(*title);
    if ((*title)[0] == '\0') return 0;
    return 1;
}

static void append_body_or_mark_oversize(const char *method,
                                        const char *upload_data,
                                        size_t *upload_data_size,
                                        struct connection_info *ci) {
    if (*upload_data_size == 0) return;

    if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) &&
        ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
        ci->data_size = NOTES_MAX_BODY_BYTES + 1;
        *upload_data_size = 0;
        return;
    }

    char *nb = realloc(ci->data, ci->data_size + *upload_data_size + 1);
    if (!nb) {
        *upload_data_size = 0;
        return;
    }

    ci->data = nb;
    memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
    ci->data_size += *upload_data_size;
    ci->data[ci->data_size] = '\0';
    *upload_data_size = 0;
}

static int parse_id_from_path(const char *url, int *out_id) {
    const char *prefix = "/api/notes/";
    size_t prelen = strlen(prefix);
    if (strncmp(url, prefix, prelen) != 0) return 0;
    const char *idstr = url + prelen;
    if (*idstr == '\0') return 0;
    if (strchr(idstr, '/')) return 0;
    return parse_int(idstr, out_id);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                             const char *method, const char *upload_data,
                             size_t *upload_data_size, void **con_cls) {

    if (strcmp(method, "OPTIONS") == 0) return send_json(connection, "", MHD_HTTP_OK);

    // MHD pattern: first call allocates per-connection state.
    if (*con_cls == NULL) {
        struct connection_info *ci0 = calloc(1, sizeof(struct connection_info));
        if (!ci0) return MHD_NO;
        *con_cls = ci0;
        return MHD_YES;
    }

    struct connection_info *ci = *con_cls;

    // Collect body for POST/PUT.
    if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) &&
        *upload_data_size > 0) {
        append_body_or_mark_oversize(method, upload_data, upload_data_size, ci);
        return MHD_YES;
    }

    if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) &&
        ci->data_size > NOTES_MAX_BODY_BYTES) {
        return too_large(connection);
    }

    // Collection routes
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        int limit = NOTES_DEFAULT_PAGE_SIZE;
        int offset = 0;

        const char *limit_s = MHD_lookup_connection_value(connection,
                                                         MHD_GET_ARGUMENT_KIND,
                                                         "limit");
        const char *offset_s = MHD_lookup_connection_value(connection,
                                                          MHD_GET_ARGUMENT_KIND,
                                                          "offset");
        if (limit_s) {
            int v;
            if (parse_int(limit_s, &v)) limit = v;
        }
        if (offset_s) {
            int v;
            if (parse_int(offset_s, &v)) offset = v;
        }
        if (limit <= 0) limit = NOTES_DEFAULT_PAGE_SIZE;
        if (limit > NOTES_MAX_PAGE_SIZE) limit = NOTES_MAX_PAGE_SIZE;
        if (offset < 0) offset = 0;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json) return send_json_total(connection, "[]", MHD_HTTP_OK, total);
        enum MHD_Result r = send_json_total(connection, json, MHD_HTTP_OK, total);
        free(json);
        return r;
    }

    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        if (!api_key_valid(connection)) return unauthorized(connection);

        char *title = NULL;
        char *content = NULL;
        if (!ci->data || !parse_note_body(ci->data, &title, &content)) {
            free(title);
            free(content);
            return bad_request(connection);
        }

        int id = create_note(title, content);
        free(title);
        free(content);

        if (id <= 0)
            return send_json(connection, "{\"error\":\"server error\"}",
                             MHD_HTTP_INTERNAL_SERVER_ERROR);

        char *row = get_note_json(id);
        if (!row)
            return send_json(connection, "{\"error\":\"server error\"}",
                             MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, row, MHD_HTTP_CREATED);
        free(row);
        return r;
    }

    // Item routes
    int id = 0;
    if (parse_id_from_path(url, &id)) {
        if (strcmp(method, "GET") == 0) {
            char *row = get_note_json(id);
            if (!row) return not_found(connection);
            enum MHD_Result r = send_json(connection, row, MHD_HTTP_OK);
            free(row);
            return r;
        }

        if (strcmp(method, "PUT") == 0) {
            if (!api_key_valid(connection)) return unauthorized(connection);
            if (!note_exists(id)) return not_found(connection);

            char *title = NULL;
            char *content = NULL;
            if (!ci->data || !parse_note_body(ci->data, &title, &content)) {
                free(title);
                free(content);
                return bad_request(connection);
            }

            int ok = update_note(id, title, content);
            free(title);
            free(content);
            if (!ok)
                return send_json(connection, "{\"error\":\"server error\"}",
                                 MHD_HTTP_INTERNAL_SERVER_ERROR);

            char *row = get_note_json(id);
            if (!row)
                return send_json(connection, "{\"error\":\"server error\"}",
                                 MHD_HTTP_INTERNAL_SERVER_ERROR);
            enum MHD_Result r = send_json(connection, row, MHD_HTTP_OK);
            free(row);
            return r;
        }

        if (strcmp(method, "DELETE") == 0) {
            if (!api_key_valid(connection)) return unauthorized(connection);
            if (!note_exists(id)) return not_found(connection);

            int ok = delete_note(id);
            if (!ok)
                return send_json(connection, "{\"error\":\"server error\"}",
                                 MHD_HTTP_INTERNAL_SERVER_ERROR);
            return send_json(connection, "{\"status\":\"deleted\"}",
                             MHD_HTTP_OK);
        }

        return not_found(connection);
    }

    return not_found(connection);
}
EOF
