static sqlite3 *db = NULL;
static pthread_mutex_t db_mu = PTHREAD_MUTEX_INITIALIZER;

static int exec_pragma(const char *sql) {
    char *err = NULL;
    int rc = sqlite3_exec(db, sql, NULL, NULL, &err);
    if (rc != SQLITE_OK) {
        fprintf(stderr, "SQLite pragma error: %s (%s)\n", err ? err : "?", sql);
        sqlite3_free(err);
        return -1;
    }
    return 0;
}

int init_db(const char *path) {
    pthread_mutex_lock(&db_mu);

    if (sqlite3_open_v2(path, &db,
                        SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE |
                            SQLITE_OPEN_FULLMUTEX,
                        NULL) != SQLITE_OK) {
        fprintf(stderr, "Cannot open database: %s\n", sqlite3_errmsg(db));
        pthread_mutex_unlock(&db_mu);
        return -1;
    }

    // Concurrency / durability tuning suitable for test workloads.
    if (exec_pragma("PRAGMA journal_mode=WAL;") != 0) {
