                snprintf(out, needed,
                         "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\"}",
                         rid, et, ec);
        }
        free(et);
        free(ec);
    }

    sqlite3_finalize(stmt);
    pthread_mutex_unlock(&db_mu);
    return out;
}

int update_note(int id, const char *title, const char *content) {
    pthread_mutex_lock(&db_mu);

    sqlite3_exec(db, "BEGIN IMMEDIATE;", NULL, NULL, NULL);

    const char *sql = "UPDATE notes SET title=?, content=? WHERE id=?;";
    sqlite3_stmt *stmt = NULL;
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return 0;
    }

    sqlite3_bind_text(stmt, 1, title ? title : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content ? content : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_int(stmt, 3, id);

    rc = sqlite3_step(stmt);
    int changed = sqlite3_changes(db);
    sqlite3_finalize(stmt);

    if (rc != SQLITE_DONE) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return 0;
    }

    sqlite3_exec(db, "COMMIT;", NULL, NULL, NULL);
    pthread_mutex_unlock(&db_mu);
    return changed > 0;
}

int delete_note(int id) {
    pthread_mutex_lock(&db_mu);

    sqlite3_exec(db, "BEGIN IMMEDIATE;", NULL, NULL, NULL);

    const char *sql = "DELETE FROM notes WHERE id=?;";
    sqlite3_stmt *stmt = NULL;
    int rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return 0;
    }

    sqlite3_bind_int(stmt, 1, id);
    rc = sqlite3_step(stmt);
    int changed = sqlite3_changes(db);
    sqlite3_finalize(stmt);

    if (rc != SQLITE_DONE) {
        sqlite3_exec(db, "ROLLBACK;", NULL, NULL, NULL);
        pthread_mutex_unlock(&db_mu);
        return 0;
    }

    sqlite3_exec(db, "COMMIT;", NULL, NULL, NULL);
    pthread_mutex_unlock(&db_mu);
    return changed > 0;
}

